import{_ as t,o,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"G11: 客戶、供應商與合作夥伴關係","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組/G09_客戶供應商與合作夥伴關係_投資研究員.md","filePath":"32Ｑ題本＿重要/經營組/G09_客戶供應商與合作夥伴關係_投資研究員.md"}'),s={name:"32Ｑ題本＿重要/經營組/G09_客戶供應商與合作夥伴關係_投資研究員.md"};function i(l,r,a,g,c,_){return o(),e("div",null,[...r[0]||(r[0]=[n('<h1 id="g11-客戶、供應商與合作夥伴關係" tabindex="-1">G11: 客戶、供應商與合作夥伴關係 <a class="header-anchor" href="#g11-客戶、供應商與合作夥伴關係" aria-label="Permalink to &quot;G11: 客戶、供應商與合作夥伴關係&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G09</li><li><strong>題目：</strong> 近三年中，前十大客戶與供應商變動情形為何？客戶集中度風險是否正在惡化？公司是否擁有具備國際指標性的關鍵合作夥伴或 Tier1 客戶？這類關係的穩定度與進入壁壘為何？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「營運風險與客戶黏性 (Customer Stickiness)」審計。擅長識別單一客戶佔比過高導致的議價力弱勢，以及主要供應商更換背後的品質、斷鏈或成本控制風險。同時能分析關鍵合作夥伴的戰略價值與穩定度。</li><li><strong>意圖：</strong> 執行「客戶集中度、供應鏈安全性與合作夥伴戰略價值審計」。判定企業是否具備分散風險的能力，識別「掉單」或「供應鏈斷裂」對營收與毛利的潛在衝擊量級，同時評估關鍵合作夥伴的戰略深度。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心事實來源：Annual Report (年報)】</strong>：必須查閱 <code>財務報告附註 -&gt; 主要客戶與夥伴資訊</code> 或 <code>業務報告</code> 章節。獲取前十大客戶之「代號」或「名稱」及其營收佔比。</li><li><strong>【外部事實確認：Google Search】</strong>：檢索「[公司名] 第一大客戶 是誰」、「[公司名] 供應鏈 轉向」、「[公司名] 核心訂單 變動」、「[公司名] 戰略合作夥伴」。</li><li><strong>【穿透校準：MOPS】</strong>：檢索「重大收購」或「大戶清算」公告，判定客戶群體結構的動態穩定性。</li></ol></li><li><strong>邏輯：</strong> 執行「客戶貢獻係數算則」——分析最近三年 Top 1 及 Top 10 客戶累計佔比趨勢；評估「供應商可替代性」——識別企業在供應鏈中的雙向博弈能力；判定「合作夥伴戰略深度」——是表面合作還是深度綁定。</li><li><strong>來源：</strong> <code>公司年報 (主要供應商與關鍵客戶明細表)</code>, <code>財務報告附註 (分部資訊)</code>, <code>產業趨勢分析報告</code>, <code>各大廠年度供應鏈名單 (Vendor List)</code></li></ul><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【客戶事實優先】</strong>：智慧體<strong>必須</strong>明確列出最近三年的「前三大客戶」及其具體百分比佔比。禁止在未明列數據前得出「穩定」或「集中」之定性結論。</li><li><strong>【掉單風險偵測】</strong>：若前十大名單發生劇烈名次更換或主要客戶突然消失，智慧體必須強制檢索原因。</li><li><strong>【掉單壓力測試 (Order-Loss Stress Test)】</strong>：智慧體<strong>必須</strong>執行假設性試算——若最大客戶 (Top 1) 營收歸零，該年度毛利率與營業費用率將如何變化？模擬公司在「最壞情境」下的利潤存活能力。</li><li><strong>【供應鏈韌性審核】</strong>：分析關鍵原物料是否依賴單一廠家，識別其毛利率是否受制於供應商漲價。</li><li><strong>【合作夥伴戰略深度】</strong>：判定合作夥伴關係是「表面合作」（採購關係）還是「深度綁定」（聯合開發、股權交叉、獨家供應）。分析合作對公司技術或市場的實質提升。</li><li><strong>【描述指標】</strong>：絕對禁用「客戶穩定」、「高度依賴」。必須量化為具體的「Top 1 佔比 %」、「前十大客戶累計營收佔比 %」與「供應商均一度」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【g11-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【G11 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【g11-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【G11 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「集中指標 + 風險鑑定 + 合作深度」結構（例：Top 1 客戶佔比 X% (屬 [高/低] 集中)，近期名單 [穩定/劇增]，掉單風險等級評定為 [嚴峻/可控]，合作夥伴關係深度評定為 [深度綁定/表面合作]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：客戶群高度分散於多個不同垂直產業，單一客戶佔比低於 15%，且主要供應商名單極度穩定，合作夥伴具備深度綁定（聯合開發/獨家供應）。</li><li><strong>A (良)</strong>：具備長期合作的指標性大客戶（佔比合理），供應鏈分散程度足以應對突發性斷鏈風險。</li><li><strong>B (持平)</strong>：極度依賴單一客戶（佔比 &gt; 50%）或特定供應商，且名單出現異常更換，面臨極高的「被收割」或「營運震盪」風險。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li><li><strong>【證據來源】數據溯源</strong>：必須精確標註年報 P.XXX 主要客戶與供應商明細表。</li><li><strong>【專家建議】注意事項</strong>：特別關注「標籤客戶 (Reference Customers)」。若公司能成功留住 Tier 1 世界級大客戶超過 5 年，代表其技術或良率具備極硬的護城河。判定這是「大樹好乘涼 (Big Account Synergy)」還是「孤注一擲 (All-in Risk)」。</li></ul>',8)])])}const u=t(s,[["render",i]]);export{h as __pageData,u as default};
